<script setup lang="ts">
import { computed, ref } from 'vue'
import { useMutation, useQuery, useQueryClient } from '@tanstack/vue-query'
import { Bell, CheckCheck, CircleAlert, Inbox, RefreshCw } from 'lucide-vue-next'
import Button from '@/components/ui/Button.vue'
import StatusBadge from '@/components/ui/StatusBadge.vue'
import { getAlerts, updateAlert, type Alert } from '@/lib/api'
const client=useQueryClient();const filter=ref<'active'|'all'>('active');const query=useQuery({queryKey:['alerts'],queryFn:getAlerts,refetchInterval:30000});const mutation=useMutation({mutationFn:({id,status}:{id:string;status:Alert['status']})=>updateAlert(id,status),onSuccess:()=>client.invalidateQueries({queryKey:['alerts']})});const items=computed(()=>filter.value==='all'?(query.data.value??[]):(query.data.value??[]).filter(item=>item.status!=='resolved'));const severity=(value:string)=>value==='critical'?'critical':value==='warning'?'warning':'info'
</script>
<template><div class="mx-auto max-w-6xl space-y-5"><header class="flex flex-col justify-between gap-4 md:flex-row md:items-end"><div><div class="flex items-center gap-2 font-mono text-[10px] uppercase tracking-widest text-signal"><Inbox class="h-3.5 w-3.5"/>Operational inbox</div><h1 class="mt-3 text-3xl font-semibold tracking-tight">Notification center</h1><p class="mt-2 text-sm text-muted">Alertas persistentes, reconhecimento explícito e resolução auditada.</p></div><Button variant="outline" @click="query.refetch()"><RefreshCw class="h-4 w-4"/>Atualizar</Button></header><div class="flex items-center gap-2"><button v-for="item in [{id:'active',label:'Ativos'},{id:'all',label:'Todos'}]" :key="item.id" :class="['cursor-pointer rounded-lg border px-3 py-2 text-xs',filter===item.id?'border-signal/30 bg-signal/10 text-signal':'border-line text-muted']" @click="filter=item.id as typeof filter">{{item.label}}</button><span class="ml-auto font-mono text-[10px] text-muted">{{items.length}} sinais</span></div><div v-if="query.isLoading.value" class="grid min-h-64 place-items-center rounded-xl border border-line bg-panel/50"><div class="h-8 w-8 animate-spin rounded-full border-2 border-line border-t-signal"/></div><div v-else-if="query.isError.value" class="rounded-xl border border-danger/20 bg-danger/5 p-4 text-sm text-danger">Não foi possível carregar a caixa operacional.</div><section v-else-if="items.length" class="space-y-3"><article v-for="alert in items" :key="alert.id" class="rounded-xl border border-line bg-panel/65 p-5"><div class="flex flex-col gap-4 sm:flex-row sm:items-start"><div :class="['grid h-10 w-10 shrink-0 place-items-center rounded-xl border',alert.severity==='critical'?'border-danger/20 bg-danger/[.07]':'border-warning/20 bg-warning/[.06]']"><CircleAlert :class="['h-5 w-5',alert.severity==='critical'?'text-danger':'text-warning']"/></div><div class="min-w-0 flex-1"><div class="flex flex-wrap items-center gap-2"><h2 class="text-sm font-medium">{{alert.title}}</h2><StatusBadge :status="severity(alert.severity)" :label="alert.severity"/><StatusBadge :status="alert.status==='resolved'?'healthy':'info'" :label="alert.status"/></div><p class="mt-2 text-xs leading-5 text-muted">{{alert.description||'Sem detalhes adicionais.'}}</p><p class="mt-3 font-mono text-[9px] uppercase tracking-wider text-muted">{{alert.resource_type}} · {{new Date(alert.created_at).toLocaleString('pt-BR')}}</p></div><div class="flex shrink-0 gap-2"><Button v-if="alert.status==='open'" variant="outline" @click="mutation.mutate({id:alert.id,status:'acknowledged'})">Reconhecer</Button><Button v-if="alert.status!=='resolved'" @click="mutation.mutate({id:alert.id,status:'resolved'})"><CheckCheck class="h-4 w-4"/>Resolver</Button><Button v-else variant="ghost" @click="mutation.mutate({id:alert.id,status:'open'})">Reabrir</Button></div></div></article></section><section v-else class="grid min-h-72 place-items-center rounded-xl border border-dashed border-line text-center"><div><Bell class="mx-auto h-8 w-8 text-muted"/><h2 class="mt-4 text-sm text-slate-200">Inbox limpa</h2><p class="mt-1 text-xs text-muted">Nenhum alerta requer atenção agora.</p></div></section></div></template>
